import React, { useState, useEffect, useCallback, useRef } from 'react';
import axios from 'axios';
import { Button } from 'primereact/button';
import { InputText } from 'primereact/inputtext';
import { TabView, TabPanel } from 'primereact/tabview';
import { ProgressSpinner } from 'primereact/progressspinner';
import { Avatar } from 'primereact/avatar';
import UserProfileDialog from './UserProfileDialog';

const API_BASE = 'http://localhost:8081/api/v1';

function FriendsPanel({ toast, user, onOpenFriend }) {
  const [friends, setFriends] = useState([]);
  const [pendingRequests, setPendingRequests] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [sentRequests, setSentRequests] = useState(new Set());
  const searchTimer = useRef(null);
  const currentUserId = user?.id;
  const [friendSort, setFriendSort] = useState('addedAt_desc');

  const sortFriends = (list) => {
    const sorted = [...list];
    switch (friendSort) {
      case 'username_asc':  return sorted.sort((a, b) => (a.username || '').localeCompare(b.username || '', 'ru'));
      case 'username_desc': return sorted.sort((a, b) => (b.username || '').localeCompare(a.username || '', 'ru'));
      case 'addedAt_desc':  return sorted.sort((a, b) => new Date(b.addedAt || 0) - new Date(a.addedAt || 0));
      case 'addedAt_asc':   return sorted.sort((a, b) => new Date(a.addedAt || 0) - new Date(b.addedAt || 0));
      case 'birthDate_asc': return sorted.sort((a, b) => new Date(a.birthDate || 0) - new Date(b.birthDate || 0));
      case 'birthDate_desc':return sorted.sort((a, b) => new Date(b.birthDate || 0) - new Date(a.birthDate || 0));
      default: return sorted;
    }
  };

  const openProfile = async (userId) => {
    try {
      const r = await axios.get(`${API_BASE}/users/${userId}`);
      onOpenFriend?.(r.data);
    } catch {}
  };

  const loadFriends = useCallback(async () => {
    try {
      const r = await axios.get(`${API_BASE}/friends`);
      setFriends(r.data.friends || []);
    } catch {}
  }, []);

  const loadPending = useCallback(async () => {
    try {
      const r = await axios.get(`${API_BASE}/friends/requests`);
      setPendingRequests(r.data.requests || []);
    } catch {}
  }, []);

  useEffect(() => {
    loadFriends();
    loadPending();
  }, [loadFriends, loadPending]);

  // Live-поиск с дебаунсом 400ms
  useEffect(() => {
    if (!searchQuery.trim()) {
      setSearchResults([]);
      return;
    }
    clearTimeout(searchTimer.current);
    searchTimer.current = setTimeout(async () => {
      setSearching(true);
      try {
        const r = await axios.get(`${API_BASE}/users/search?q=${encodeURIComponent(searchQuery)}`);
        setSearchResults(r.data.users || []);
      } catch {
        toast.current?.show({ severity: 'error', summary: 'Ошибка поиска', life: 2000 });
      } finally {
        setSearching(false);
      }
    }, 400);
    return () => clearTimeout(searchTimer.current);
  }, [searchQuery, toast]);

  const friendIds = new Set(friends.map(f => f.id));

  const sendRequest = async (friendId) => {
    try {
      await axios.post(`${API_BASE}/friends/request`, { friendId });
      setSentRequests(prev => new Set([...prev, friendId]));
      toast.current?.show({ severity: 'success', summary: 'Запрос отправлен', life: 2000 });
    } catch (e) {
      toast.current?.show({ severity: 'error', summary: e.response?.data?.error || 'Ошибка', life: 2000 });
    }
  };

  const acceptRequest = async (friendshipId) => {
    try {
      await axios.post(`${API_BASE}/friends/requests/${friendshipId}/accept`, {});
      toast.current?.show({ severity: 'success', summary: 'Запрос принят', life: 2000 });
      loadFriends();
      loadPending();
    } catch {}
  };

  const rejectRequest = async (friendshipId) => {
    try {
      await axios.post(`${API_BASE}/friends/requests/${friendshipId}/reject`, {});
      toast.current?.show({ severity: 'info', summary: 'Запрос отклонён', life: 2000 });
      loadPending();
    } catch {}
  };

  const removeFriend = async (friendId) => {
    try {
      await axios.delete(`${API_BASE}/friends/${friendId}`);
      toast.current?.show({ severity: 'info', summary: 'Друг удалён', life: 2000 });
      loadFriends();
    } catch {}
  };

  const getSearchButtonState = (userId) => {
    if (userId === currentUserId) return { disabled: true, label: 'Это вы', icon: 'pi pi-user' };
    if (friendIds.has(userId)) return { disabled: true, label: 'Уже друг', icon: 'pi pi-check' };
    if (sentRequests.has(userId)) return { disabled: true, label: 'Запрос отправлен', icon: 'pi pi-clock' };
    return { disabled: false, label: 'Добавить', icon: 'pi pi-user-plus' };
  };

  return (
    <div>
      <TabView className="friends-tabs">
        <TabPanel header="Друзья">
          {friends.length === 0 ? (
            <div style={{
              width: '945px',
              height: '482px',
              background: '#FFFFFF',
              borderRadius: '14px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto',
              position: 'relative',
              gap: '24px'
            }}>
              <img 
                src="/images/us1.svg" 
                alt="Персонажи" 
                style={{ 
                  width: 'auto', 
                  height: '240px',
                  marginBottom: '16px'
                }} 
              />
              <div style={{ textAlign: 'center' }}>
                <h2 style={{ 
                  fontSize: '20px', 
                  fontWeight: '700', 
                  color: '#1e293b', 
                  margin: '0 0 8px 0' 
                }}>
                  Здесь пока пусто
                </h2>
                <p style={{ 
                  fontSize: '16px', 
                  fontWeight: '400', 
                  color: '#64748b', 
                  margin: '0' 
                }}>
                  Скопируйте ссылку на профиль и поделитесь с друзьями
                </p>
              </div>
            </div>
          ) : (
            <div className="flex flex-column gap-2 mt-2">
              <div className="flex justify-content-start mb-2">
                <div style={{ position: 'relative', width: '300px' }}>
                  <i className="pi pi-sort-alt" style={{ 
                    position: 'absolute', 
                    left: '12px', 
                    top: '50%', 
                    transform: 'translateY(-50%)',
                    fontSize: '16px',
                    color: '#1e293b',
                    pointerEvents: 'none',
                    zIndex: 1
                  }}></i>
                  <select
                    value={friendSort}
                    onChange={e => setFriendSort(e.target.value)}
                    className=""
                    style={{ 
                      fontSize: '14px', 
                      padding: '0 40px 0 40px', 
                      borderRadius: '12px', 
                      border: '2px solid #18B700',
                      color: '#1e293b',
                      width: '100%',
                      height: '40px',
                      lineHeight: '40px',
                      appearance: 'none',
                      WebkitAppearance: 'none',
                      backgroundImage: 'url("/images/path.svg")',
                      backgroundRepeat: 'no-repeat',
                      backgroundPosition: 'right 12px center',
                      backgroundSize: '9px 5px',
                      cursor: 'pointer',
                      outline: 'none',
                      backgroundColor: '#fff',
                      fontFamily: 'inherit',
                    }}
                  >
                    <option value="addedAt_desc">По дате добавления (новые)</option>
                    <option value="addedAt_asc">По дате добавления (старые)</option>
                    <option value="username_asc">По имени (А–Я)</option>
                    <option value="username_desc">По имени (Я–А)</option>
                    <option value="birthDate_asc">По дате рождения</option>
                    <option value="birthDate_desc">По дате рождения (дальние)</option>
                  </select>
                </div>
              </div>
              {sortFriends(friends).map(f => (
                <div key={f.friendshipId} className="friend-card">
                  <div className="flex align-items-center gap-3">
                    <Avatar
                      label={f.username?.charAt(0).toUpperCase()}
                      shape="circle"
                      style={{ 
                        background: '#188700', 
                        color: 'white', 
                        cursor: 'pointer',
                        width: '49px',
                        height: '49px',
                        fontSize: '20px',
                        fontWeight: '600'
                      }}
                      onClick={() => openProfile(f.id)}
                    />
                    <div>
                      <div className="font-semibold">{f.username}</div>
                      <div className="text-color-secondary text-sm">{f.email}</div>
                    </div>
                  </div>
                  <button
                    onClick={() => removeFriend(f.id)}
                    style={{
                      width: '35px',
                      height: '35px',
                      minWidth: '35px',
                      minHeight: '35px',
                      borderRadius: '8px',
                      background: '#FFE5E5',
                      border: 'none',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      cursor: 'pointer',
                      transition: 'background 0.2s'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.background = '#FFD0D0'}
                    onMouseLeave={(e) => e.currentTarget.style.background = '#FFE5E5'}
                  >
                    <i className="pi pi-trash" style={{ fontSize: '16px', color: '#DC2626' }}></i>
                  </button>
                </div>
              ))}
            </div>
          )}
        </TabPanel>

        <TabPanel header="Заявки">
          {pendingRequests.length === 0 ? (
            <div style={{
              width: '945px',
              height: '482px',
              background: '#FFFFFF',
              borderRadius: '14px',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto',
              position: 'relative',
              gap: '24px'
            }}>
              <img 
                src="/images/us2.svg" 
                alt="Персонаж" 
                style={{ 
                  width: 'auto', 
                  height: '240px',
                  marginBottom: '16px'
                }} 
              />
              <div style={{ textAlign: 'center' }}>
                <h2 style={{ 
                  fontSize: '20px', 
                  fontWeight: '700', 
                  color: '#1e293b', 
                  margin: '0 0 8px 0' 
                }}>
                  Здесь пока пусто
                </h2>
                <p style={{ 
                  fontSize: '16px', 
                  fontWeight: '400', 
                  color: '#64748b', 
                  margin: '0' 
                }}>
                  Вы еще не получили заявок в друзья
                </p>
              </div>
            </div>
          ) : (
            <div className="flex flex-column gap-2 mt-2">
              {pendingRequests.map(req => (
                <div key={req.friendshipId} className="friend-card">
                  <div className="flex align-items-center gap-3">
                    <Avatar
                      label={req.username?.charAt(0).toUpperCase()}
                      shape="circle"
                      style={{ 
                        background: '#188700', 
                        color: 'white', 
                        cursor: 'pointer',
                        width: '49px',
                        height: '49px',
                        fontSize: '20px',
                        fontWeight: '600'
                      }}
                      onClick={() => openProfile(req.id)}
                    />
                    <div>
                      <div className="font-semibold">{req.username}</div>
                      <div className="text-color-secondary text-sm">{req.email}</div>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button
                      onClick={() => acceptRequest(req.friendshipId)}
                      style={{
                        padding: '8px 24px',
                        borderRadius: '20px',
                        background: '#188700',
                        color: 'white',
                        border: 'none',
                        fontSize: '16px',
                        fontWeight: '500',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        transition: 'background 0.2s'
                      }}
                      onMouseEnter={(e) => e.currentTarget.style.background = '#146600'}
                      onMouseLeave={(e) => e.currentTarget.style.background = '#188700'}
                    >
                      Принять
                    </button>
                    <button
                      onClick={() => rejectRequest(req.friendshipId)}
                      style={{
                        padding: '8px 24px',
                        borderRadius: '20px',
                        background: 'white',
                        color: '#DC2626',
                        border: '2px solid #DC2626',
                        fontSize: '16px',
                        fontWeight: '500',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        transition: 'all 0.2s'
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = '#FEE2E2';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = 'white';
                      }}
                    >
                      Отклонить
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </TabPanel>

        <TabPanel header="Запросы">
          <div className="mt-2">
            <InputText
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              placeholder="Введите имя или email..."
              className="w-full"
            />

            <div className="flex flex-column gap-2 mt-3">
              {searchResults
                .filter(u => u.id !== currentUserId)
                .map(u => {
                  const btn = getSearchButtonState(u.id);
                  return (
                    <div key={u.id} className="friend-card">
                      <div className="flex align-items-center gap-3">
                        <Avatar
                          label={u.username?.charAt(0).toUpperCase()}
                          shape="circle"
                          style={{ 
                            background: '#188700', 
                            color: 'white', 
                            cursor: 'pointer',
                            width: '49px',
                            height: '49px',
                            fontSize: '20px',
                            fontWeight: '600'
                          }}
                          onClick={() => openProfile(u.id)}
                        />
                        <div>
                          <div className="font-semibold">{u.username}</div>
                          <div className="text-color-secondary text-sm">{u.email}</div>
                        </div>
                      </div>
                      <button
                        disabled={btn.disabled}
                        onClick={() => sendRequest(u.id)}
                        style={{
                          width: '87px',
                          height: '35px',
                          borderRadius: '20px',
                          background: btn.disabled ? '#cccccc' : '#188700',
                          color: 'white',
                          border: 'none',
                          fontSize: '14px',
                          fontWeight: '600',
                          cursor: btn.disabled ? 'not-allowed' : 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          transition: 'all 0.2s'
                        }}
                        onMouseEnter={(e) => {
                          if (!btn.disabled) e.currentTarget.style.background = '#146600';
                        }}
                        onMouseLeave={(e) => {
                          if (!btn.disabled) e.currentTarget.style.background = '#188700';
                        }}
                      >
                        {btn.label}
                      </button>
                    </div>
                  );
                })}

              {!searching && searchQuery.trim() && searchResults.filter(u => u.id !== currentUserId).length === 0 && (
                <div style={{
                  width: '945px',
                  height: '482px',
                  background: '#FFFFFF',
                  borderRadius: '14px',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  margin: '0 auto',
                  position: 'relative',
